mapper.select:
SELECT rr.id, rr.review_id, rr.user_id, COALESCE(u.nickname, u.username) AS nickname, u.avatar_url AS avatarUrl, rr.content, rr.create_time FROM review_reply rr LEFT JOIN users u ON rr.user_id = u.id WHERE rr.is_deleted = 0 AND rr.review_id IN
#{reviewId}
ORDER BY rr.create_time ASC, rr.id ASC

mapper.update:
UPDATE university_review
SET is_deleted = 1
WHERE id = #{reviewId}
  AND user_id = #{userId}
  AND is_deleted = 0

mapper.delete:
DELETE FROM review_like
WHERE review_id = #{reviewId}
  AND user_id = #{userId}

mapper.update:
UPDATE review_reply
SET is_deleted = 1
WHERE id = #{replyId}
  AND user_id = #{userId}
